3	/**
4	 * End-to-end suite: spawns the real CLI, generates PNGs, asserts naming + pixels.
5	 */
6	const assert = require('node:assert/strict');
7	const { spawnSync } = require('node:child_process');
8	const fs = require('node:fs');
9	const fsp = require('node:fs/promises');
