15	const ROOT = __dirname;
16	const CLI = path.join(ROOT, 'cli.js');
17	const NAME_RE = /^card_\d{4}(?:_\d{2}){5}_[A-Za-z0-9_]+\.png$/;
18	
19	function run(args, cwd) {
20	  const result = spawnSync(process.execPath, [CLI, ...args], {
21	    cwd,
22	    encoding: 'utf8',
23	    env: { ...process.env }
24	  });
25	  return result;
26	}
