28	function assertOk(result, label) {
29	  assert.equal(result.status, 0, `${label} failed:\nstdout: ${result.stdout}\nstderr: ${result.stderr}`);
30	}
31	
32	async function assertCardImage(filePath, label) {
33	  const stat = await fsp.stat(filePath);
34	  assert.ok(stat.size > 5_000, `${label}: file too small (${stat.size} bytes)`);
35	
36	  const metadata = await sharp(filePath).metadata();
37	  assert.equal(metadata.width, 1920, `${label}: width`);
38	  assert.equal(metadata.height, 1080, `${label}: height`);
39	  assert.equal(metadata.format, 'png', `${label}: format`);
40	
41	  const stats = await sharp(filePath).stats();
42	  // Text is near-black on cream; min channel should drop well below background.
43	  assert.ok(stats.channels[0].min < 80, `${label}: expected dark text pixels`);
44	  assert.ok(stats.channels[0].max > 200, `${label}: expected light background`);
45	}
